import React, { use, useCallback, useEffect, useState } from 'react';
import { Streamlit, withStreamlitConnection } from 'streamlit-component-lib';
import ReactFlow, { addEdge, Controls, Background } from "react-flow-renderer";
import "react-flow-renderer-gd/dist/style.css"
import dagre from "dagre";

//========== dagre自动布局函数 ============//
const nodeWidth = 180;
const nodeHeight = 60;

const getLayoutedElements = (nodes, edges, direction = "TB") => {
    const isHorizontal = direction === "LR";
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));
    dagreGraph.setGraph({ rankdir: direction });
    
    //注册节点
    nodes.forEach((node) => {
        dagreGraph.setNode(node.id, { width: nodeWidth, height: nodeHeight });
    });

    //注册边
    edges.forEach((edge) => {
        dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
        const nodeWithPosition = dagreGraph.node(node.id);
        node.targetPosition = isHorizontal ? "left" : "top";
        node.sourcePosition = isHorizontal ? "right" : "bottom";
        return {
            ...node,
            position: {
                x: nodeWithPosition.x - nodeWidth / 2,
                y: nodeWithPosition.y - nodeHeight / 2,
            },
        };
    });
    return { nodes: layoutedNodes, edges };
}

function GraphViewer({ args }) {
    //初始化页面,只执行一次
    useEffect(() => {
        Streamlit.setComponentReady();
        Streamlit.setFrameHeight(800);  // 设置组件高度，确保有足够空间显示图
    }, [])

    const [nodes, setNodes] = useState([]);
    const [edges, setEdges] = useState([]);
    useEffect(() => {
        if (!args.graph) return;
        const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(args.graph.nodes || [], args.graph.edges || [], "TB");
        setNodes(layoutedNodes);
        setEdges(layoutedEdges);

    // const [nodes, setNodes] = useState(args.graph?.nodes || []);
    // const [edges, setEdges] = useState(args.graph?.edges || []);
    
    // useEffect(() => {
    //     if (args.graph) {
    //         setNodes(args.graph.nodes || []);
    //         setEdges(args.graph.edges || []);
    //     }
    }, [args.graph])

    //用户连线
    const onConnect = useCallback((params) => {
        console.log("触发连接:", params);
        setEdges((eds) => {
            const updatedEdges = addEdge(params, eds);
            Streamlit.setComponentValue({
                graph: { nodes, edges: updatedEdges }
            })
            return updatedEdges;
        });    
    }, [nodes])

    //用户拖动节点后更新图数据
    // const onNodeDragStop = useCallback(() => {
    //     Streamlit.setComponentValue({
    //         graph: { nodes, edges }
    //     })
    // }, [nodes, edges])
    const onNodeDragStop = useCallback((_, node) => {
        console.log("节点拖动结束:", node);
        const updatedNodes = nodes.map((n) => (n.id === node.id ? { ...n, position: node.position } : n));
        setNodes(updatedNodes);
        Streamlit.setComponentValue({
            graph: { nodes: updatedNodes, edges }
        });
    }, [nodes, edges])

    return (
    <div style={{ width: "100%", height: "800px"}}>
    <ReactFlow
        nodes={nodes}
        edges={edges}
        onConnect={onConnect}
        onNodeDragStop={onNodeDragStop}
        fitView //自动缩放到视图
    >
        <Controls />
        <Background />
    </ReactFlow>
    </div>
    );
}
    export default withStreamlitConnection(GraphViewer);
